'use client';

import { Mesh, Program, Renderer, Triangle } from 'ogl';
import { useDeferredValue, useEffect, useRef } from 'react';

import { cn } from '@/lib/utils';
import { mergeRefs, useInView, usePrefersReducedMotion } from '@/lib/containment';

// ─── Types ────────────────────────────────────────────────────────────────────

export type EmberDriftProps = {
	className?: string;
	/** Deep base tone — leftmost aurora colour stop (6-char hex). */
	color1?: string;
	/** Mid-range glow tone (6-char hex). */
	color2?: string;
	/** Brightest heat highlight — rightmost colour stop (6-char hex). */
	color3?: string;
	/** Aurora wave height multiplier. */
	amplitude?: number;
	/** Aurora edge softness (0–1). */
	blend?: number;
	/** Shader speed multiplier. */
	speed?: number;
	/** React 19: passed as a plain prop — no forwardRef needed. */
	ref?: React.Ref<HTMLDivElement>;
};

// ─── GLSL — same simplex-noise aurora shader as GridAurora ───────────────────

const VERT = `#version 300 es
in vec2 position;
void main() { gl_Position = vec4(position, 0.0, 1.0); }`;

const FRAG = `#version 300 es
precision highp float;

uniform float uTime;
uniform float uAmplitude;
uniform vec3  uColorStops[3];
uniform vec2  uResolution;
uniform float uBlend;
uniform float uSpeed;

out vec4 fragColor;

vec3 permute(vec3 x) { return mod(((x * 34.0) + 1.0) * x, 289.0); }

float snoise(vec2 v) {
  const vec4 C = vec4(0.211324865405187, 0.366025403784439, -0.577350269189626, 0.024390243902439);
  vec2 i   = floor(v + dot(v, C.yy));
  vec2 x0  = v - i + dot(i, C.xx);
  vec2 i1  = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy  -= i1;
  i = mod(i, 289.0);
  vec3 p  = permute(permute(i.y + vec3(0.0, i1.y, 1.0)) + i.x + vec3(0.0, i1.x, 1.0));
  vec3 m  = max(0.5 - vec3(dot(x0, x0), dot(x12.xy, x12.xy), dot(x12.zw, x12.zw)), 0.0);
  m = m * m * m * m;
  vec3 x  = 2.0 * fract(p * C.www) - 1.0;
  vec3 h  = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * (a0 * a0 + h * h);
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

struct ColorStop { vec3 color; float position; };

#define COLOR_RAMP(colors, factor, finalColor) {                              \
  int index = 0;                                                              \
  for (int i = 0; i < 2; i++) {                                              \
    ColorStop cc = colors[i];                                                 \
    bool between = cc.position <= factor;                                     \
    index = int(mix(float(index), float(i), float(between)));                \
  }                                                                           \
  ColorStop cc = colors[index]; ColorStop nc = colors[index + 1];            \
  float lerpF = (factor - cc.position) / (nc.position - cc.position);        \
  finalColor = mix(cc.color, nc.color, lerpF);                               \
}

void main() {
  vec2 uv = gl_FragCoord.xy / uResolution;

  ColorStop colors[3];
  colors[0] = ColorStop(uColorStops[0], 0.0);
  colors[1] = ColorStop(uColorStops[1], 0.5);
  colors[2] = ColorStop(uColorStops[2], 1.0);

  vec3 rampColor;
  COLOR_RAMP(colors, uv.x, rampColor);

  float t = uTime * uSpeed;
  float h = snoise(vec2(uv.x * 2.0 + t * 0.1, t * 0.25)) * 0.5 * uAmplitude;
  h = exp(h);
  h = uv.y * 2.0 - h + 0.2;

  float intensity   = 0.6 * h;
  float auroraAlpha = smoothstep(0.20 - uBlend * 0.5, 0.20 + uBlend * 0.5, intensity);

  fragColor = vec4(intensity * rampColor * auroraAlpha, auroraAlpha);
}`;

// ─── Helpers ──────────────────────────────────────────────────────────────────

function hexToRgb(hex: string): [number, number, number] {
	const h = hex.replace('#', '');
	return [parseInt(h.slice(0, 2), 16) / 255, parseInt(h.slice(2, 4), 16) / 255, parseInt(h.slice(4, 6), 16) / 255];
}

function hexToRgba(hex: string, alpha: number): string {
	const h = hex.replace('#', '');
	return `rgba(${parseInt(h.slice(0, 2), 16)},${parseInt(h.slice(2, 4), 16)},${parseInt(h.slice(4, 6), 16)},${alpha})`;
}

// ─── Component ────────────────────────────────────────────────────────────────

/**
 * CSS volcanic-ember radial gradient (pattern-craft style) as a permanent base,
 * with the react-bits ogl Aurora shader (simplex-noise bands) screen-blended above.
 *
 * The Aurora uses the same proven shader as `GridAurora` but with red/amber colour
 * stops so the flowing bands read as heat shimmer rising off the volcanic gradient.
 *
 * - Layer 1 (bottom): CSS 3-ellipse volcanic gradient — instant, zero JS.
 * - Layer 2 (top):    ogl Aurora (transparent, screen-blend) — pauses off-screen.
 * - Reduced-motion:   CSS gradient only.
 *
 * React 19: `ref` accepted as a plain prop — no `forwardRef` wrapper.
 */
export function EmberDrift({
	ref,
	className,
	color1 = '#dc2626',
	color2 = '#f97316',
	color3 = '#fde68a',
	amplitude = 1.4,
	blend = 0.7,
	speed = 0.8,
}: EmberDriftProps) {
	const reducedMotion = usePrefersReducedMotion();
	const { ref: inViewRef, inView } = useInView();
	const rootRef = useRef<HTMLDivElement>(null);
	const auroraRef = useRef<HTMLDivElement>(null);

	const inViewMut = useRef(inView);
	useEffect(() => {
		inViewMut.current = inView;
	}, [inView]);

	const dColor1 = useDeferredValue(color1);
	const dColor2 = useDeferredValue(color2);
	const dColor3 = useDeferredValue(color3);
	const dSpeed = useDeferredValue(speed);
	const dAmplitude = useDeferredValue(amplitude);
	const dBlend = useDeferredValue(blend);

	// ogl Aurora — restarts when colours or reducedMotion changes
	useEffect(() => {
		if (reducedMotion) return;

		const container = auroraRef.current;
		if (!container) return;

		const renderer = new Renderer({ alpha: true, premultipliedAlpha: false });
		const gl = renderer.gl;
		gl.clearColor(0, 0, 0, 0);
		container.appendChild(gl.canvas);

		const geometry = new Triangle(gl);
		const [r1, g1, b1] = hexToRgb(dColor1);
		const [r2, g2, b2] = hexToRgb(dColor2);
		const [r3, g3, b3] = hexToRgb(dColor3);

		const program = new Program(gl, {
			vertex: VERT,
			fragment: FRAG,
			uniforms: {
				uTime: { value: 0 },
				uAmplitude: { value: dAmplitude },
				uSpeed: { value: dSpeed },
				uBlend: { value: dBlend },
				uResolution: { value: new Float32Array([gl.canvas.width, gl.canvas.height]) },
				uColorStops: {
					value: new Float32Array([r1, g1, b1, r2, g2, b2, r3, g3, b3]),
				},
			},
		});
		const mesh = new Mesh(gl, { geometry, program });

		function resize() {
			if (!container) return;
			const dpr = window.devicePixelRatio || 1;
			const w = container.clientWidth;
			const h = container.clientHeight;
			renderer.setSize(w * dpr, h * dpr);
			gl.canvas.style.width = `${w}px`;
			gl.canvas.style.height = `${h}px`;
			program.uniforms.uResolution.value = new Float32Array([gl.canvas.width, gl.canvas.height]);
		}
		window.addEventListener('resize', resize);
		resize();

		let rafId: number;
		const update = (t: number) => {
			rafId = requestAnimationFrame(update);
			if (!inViewMut.current) return;

			program.uniforms.uTime.value = t * 0.001;
			program.uniforms.uAmplitude.value = dAmplitude;
			program.uniforms.uSpeed.value = dSpeed;
			program.uniforms.uBlend.value = dBlend;
			renderer.render({ scene: mesh });
		};
		rafId = requestAnimationFrame(update);

		return () => {
			cancelAnimationFrame(rafId);
			window.removeEventListener('resize', resize);
			if (container.contains(gl.canvas)) container.removeChild(gl.canvas);
			gl.getExtension('WEBGL_lose_context')?.loseContext();
		};
	}, [reducedMotion, dColor1, dColor2, dColor3]);

	// CSS base: volcanic-ember multi-ellipse radial gradient
	const baseStyle: React.CSSProperties = {
		background: [
			`radial-gradient(ellipse 130% 75% at 65% 85%, ${hexToRgba(color1, 0.55)} 0%, transparent 52%)`,
			`radial-gradient(ellipse 170% 50% at 25% 25%, ${hexToRgba(color1, 0.38)} 0%, transparent 58%)`,
			`radial-gradient(ellipse 90% 110% at 8% 65%, ${hexToRgba(color2, 0.28)} 0%, transparent 46%)`,
			`radial-gradient(ellipse 80% 60% at 80% 10%, ${hexToRgba(color2, 0.18)} 0%, transparent 50%)`,
			'#1c1917',
		].join(', '),
	};

	return (
		<div
			ref={mergeRefs(ref, inViewRef, rootRef)}
			className={cn('relative h-full w-full overflow-hidden', className)}
		>
			{/* Layer 1 (bottom): CSS volcanic gradient — pattern-craft style */}
			<div className="pointer-events-none absolute inset-0" style={baseStyle} aria-hidden />

			{/* Layer 2 (top): ogl Aurora with ember colour stops — screen-blends heat bands into the gradient */}
			{!reducedMotion && (
				<div
					ref={auroraRef}
					className="pointer-events-none absolute inset-0"
					style={{ mixBlendMode: 'screen' }}
					aria-hidden
				/>
			)}
		</div>
	);
}
